# E2-Skeptic three-route assess for S48-T1-A-E2
def assess(record: dict) -> str:
    required = {'query', 'expected_top', 'version', 'metric', 'docs', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (min(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) == record["expected_top"])
    except Exception:
        return 'REJECT_EMBEDDING_RANK'
    return 'PASS' if ok else 'REJECT_EMBEDDING_RANK'

record = {"case_id": "CASO-PUN-048-1A", **{"query":[1.0,0.0],"docs":{"d1":[0.8,0.2],"d2":[0.1,0.9]},"metric":"dot","version":"emb-v2","expected_top":"d1"}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'expected_top'}
print(assess(valid), assess(invalid), assess(incomplete))

